# tests/security/test_post_patch_genai_compatibility.py
"""
Tests run after every LLM SDK or prompt-related dependency patch
to detect silent API behaviour regressions.
"""
import pytest
from anthropic import Anthropic

@pytest.fixture
def client():
    return Anthropic()  # uses ANTHROPIC_API_KEY env var

@pytest.mark.post_patch
def test_tool_use_api_format_unchanged(client):
    """Verify tool_use response format has not changed after SDK upgrade."""
    response = client.messages.create(
        model="claude-3-5-haiku-20241022",
        max_tokens=256,
        tools=[{
            "name": "get_weather",
            "description": "Get weather for a location",
            "input_schema": {
                "type": "object",
                "properties": {"location": {"type": "string"}},
                "required": ["location"],
            }
        }],
        messages=[{"role": "user", "content": "What is the weather in London?"}],
    )
    tool_use_blocks = [b for b in response.content if b.type == "tool_use"]
    assert len(tool_use_blocks) >= 1, "Expected tool_use block in response"
    tool = tool_use_blocks[0]
    assert tool.name == "get_weather"
    assert "location" in tool.input

@pytest.mark.post_patch
def test_streaming_response_format_unchanged(client):
    """Verify streaming response events have not changed format."""
    event_types = set()
    with client.messages.stream(
        model="claude-3-5-haiku-20241022",
        max_tokens=64,
        messages=[{"role": "user", "content": "Say hello."}],
    ) as stream:
        for event in stream:
            event_types.add(type(event).__name__)
    required_types = {"RawMessageStartEvent", "RawContentBlockDeltaEvent", "RawMessageStopEvent"}
    assert required_types.issubset(event_types), f"Missing event types: {required_types - event_types}"
